import{_ as a,o as i,c as e,ak as t}from"./chunks/framework.d_5_XLDx.js";const c=JSON.parse('{"title":"飞牛OS通过docker安装OneDrive备份文件(超多废话版)","description":"","frontmatter":{"title":"飞牛OS通过docker安装OneDrive备份文件(超多废话版)","createTime":"2025/01/06 12:15:17","permalink":"/article/aofygutj/","tags":["飞牛OS","docker","OneDrive","备份","文件"]},"headers":[],"relativePath":"blog/ermao/文档/飞牛OS通过OneDrive备份文件.md","filePath":"blog/ermao/文档/飞牛OS通过OneDrive备份文件.md","lastUpdated":1769775157000}'),n={name:"blog/ermao/文档/飞牛OS通过OneDrive备份文件.md"};function p(l,s,h,d,o,r){return i(),e("div",null,[...s[0]||(s[0]=[t(`<p>手把手教学飞牛OS如何通过docker安装OneDrive备份文件</p><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>飞牛OS本身可以很方便的通过百度网盘跟阿里云盘做备份。</p><p>但是众所周知，你们的部分资源是不能存储在国内的网盘中（密码箱也不行）</p><p><img src="https://image.ermao.net/images/article/aofygutj/image.png" alt="alt text"></p><p>所以不得不将她们备份到国外混乱不堪的环境中。</p><p>今天就来手把手教你如何通过 OneDrive 备份文件。</p><h2 id="注册-onedrive" tabindex="-1">注册 OneDrive <a class="header-anchor" href="#注册-onedrive" aria-label="Permalink to &quot;注册 OneDrive&quot;">​</a></h2><p>你必须得有个微软账号，如果没有的话，你可以去注册一个。</p><p><a href="https://signup.live.com/" target="_blank" rel="noreferrer">官网地址</a></p><p>同时推荐在淘宝找人拼车买个 Microsoft 365，这会使你的 OneDrive 空间变成 1T。</p><h2 id="登入飞牛os后台命令行" tabindex="-1">登入飞牛OS后台命令行 <a class="header-anchor" href="#登入飞牛os后台命令行" aria-label="Permalink to &quot;登入飞牛OS后台命令行&quot;">​</a></h2><p>因为登陆时需要<code>交互式操作</code>，所以我们需要登陆后台命令行。</p><p>首先我们开启飞牛OS的 SSH 功能。</p><p><img src="https://image.ermao.net/images/article/aofygutj/image-1.png" alt="alt text"></p><p>然后在你本地终端登陆你的飞牛OS后台。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 飞牛用户名@飞牛地址</span></span></code></pre></div><p>如下图</p><p><img src="https://image.ermao.net/images/article/aofygutj/image-2.png" alt="alt text"></p><p>密码就是你的飞牛OS后台密码。注意，输入密码时是不会显示的，直接往上敲就可以了。</p><p>如果用户名、IP、密码都正确的话，你就可以登陆成功了。</p><p><img src="https://image.ermao.net/images/article/aofygutj/image-3.png" alt="alt text"></p><h2 id="切换为-root-用户" tabindex="-1">切换为 root 用户 <a class="header-anchor" href="#切换为-root-用户" aria-label="Permalink to &quot;切换为 root 用户&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> su</span></span></code></pre></div><p>这里需要再输入一次密码，直接输入就好了。</p><p><img src="https://image.ermao.net/images/article/aofygutj/image-4.png" alt="alt text"></p><p>你的用户名后面的<code>$</code>变成了<code>#</code>，这就表示你已经切换为 root 用户了。</p><h2 id="准备好配置文件的目录" tabindex="-1">准备好配置文件的目录 <a class="header-anchor" href="#准备好配置文件的目录" aria-label="Permalink to &quot;准备好配置文件的目录&quot;">​</a></h2><p>在飞牛OS后台，通常文件会在<code>/vol1/1000/你的用户名/</code>目录下。</p><p>其中<code>vol1</code>是存储池的编号，<code>1000</code>是你的用户编号。</p><p>你也可以依次点击 <code>文件管理</code> -&gt; <code>我的文件</code> -&gt; <code>右键目录</code> -&gt; <code>详细信息</code> -&gt; <code>复制原始路径</code> 来获取你的目录的路径。</p><p><img src="https://image.ermao.net/images/article/aofygutj/image-5.png" alt="alt text"></p><p>获取到了目录之后，我们给这个目录创建一个文件夹，用来持久化存储容器的配置文件。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /vol1/1000/你的用户名/docker/onedrive/conf/</span></span></code></pre></div><p>这个路径按你自己实际情况来就可以。</p><h2 id="拉取镜像、创建容器" tabindex="-1">拉取镜像、创建容器 <a class="header-anchor" href="#拉取镜像、创建容器" aria-label="Permalink to &quot;拉取镜像、创建容器&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onedrive</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /vol1/1000/你的用户名/docker/onedrive/conf/:/onedrive/conf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 需要被同步的路径:/onedrive/data</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ONEDRIVE_UID=1000&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ONEDRIVE_GID=1000&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    driveone/onedrive:latest</span></span></code></pre></div><p>记得把上面的两处汉字<code>你的用户名</code>跟<code>需要被同步的路径</code>替换实际的值。</p><p>例如这个例子：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onedrive</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /vol1/1000/emz/docker/onedrive/conf:/onedrive/conf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /vol1/1000/emz/同步/onedrive:/onedrive/data</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ONEDRIVE_UID=1000&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ONEDRIVE_GID=1000&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    driveone/onedrive:latest</span></span></code></pre></div><p>容器启动后，会提示你登陆 OneDrive。点击其中的链接，然后登陆你的 OneDrive 账号。这时候会跳转到一个页面，需要复制这个页面的地址，然后回到终端，粘贴到终端中，回车。</p><p><img src="https://image.ermao.net/images/article/aofygutj/image-6.png" alt="alt text"></p><p><img src="https://image.ermao.net/images/article/aofygutj/image-7.png" alt="alt text"></p><p>成功登陆后，容器会自动开始同步你的文件。</p><p><img src="https://image.ermao.net/images/article/aofygutj/image-8.png" alt="alt text"></p><p>同时你的配置文件中也会多出来一个名叫<code>refresh_token</code>的文件，这个文件是用来保存你的登陆信息的。如果以后修改了微软密码，需要将这个文件删除，然后重复上面的步骤。</p><p>如果以后想迁移到其他地方，可以直接把整个<code>conf</code>文件夹拷贝过去。</p><p><img src="https://image.ermao.net/images/article/aofygutj/image-9.png" alt="alt text"></p><h2 id="后台持久运行" tabindex="-1">后台持久运行 <a class="header-anchor" href="#后台持久运行" aria-label="Permalink to &quot;后台持久运行&quot;">​</a></h2><p>上面的步骤是首次登陆时需要交互式操作，但是 <code>ctrl + c</code> 退出后，容器就会停止。</p><p>我们需要重新启动容器，并且让容器在后台持久运行。</p><p>首先删除之前的容器</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onedrive</span></span></code></pre></div><p>然后重新启动容器，跟首次部署不同的是，其中<code>-it</code>改为<code>-d</code>，同时添加<code>--restart always</code>。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onedrive</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> always</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /vol1/1000/你的用户名/docker/onedrive/conf/:/onedrive/conf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 需要被同步的路径:/onedrive/data</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ONEDRIVE_UID=1000&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ONEDRIVE_GID=1000&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    driveone/onedrive:latest</span></span></code></pre></div><p>启动成功后，容器会在后台持久运行。并且飞牛OS的容器管理中也可以看到该容器了。</p><p><img src="https://image.ermao.net/images/article/aofygutj/image-10.png" alt="alt text"></p><p>在运行日志中还可以看到容器的运行情况。</p><p><img src="https://image.ermao.net/images/article/aofygutj/image-11.png" alt="alt text"></p><h2 id="配置文件" tabindex="-1">配置文件 <a class="header-anchor" href="#配置文件" aria-label="Permalink to &quot;配置文件&quot;">​</a></h2><p><code>/vol1/1000/你的用户名/docker/onedrive/conf/</code>目录下有一个名字叫<code>config</code>的文件，这个文件是容器的配置文件。</p><p>你可以通过修改它来优化同步效果。</p><p>例如这是我的配置文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 容器中的需要被同步的目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sync_dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/onedrive/data&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 自定义哪些文件夹不被同步，这里是双向的，本地和云端都生效（本地的不会上传，云端的不会下载）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">skip_dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;~*|.~*|*.tmp&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 忽略所有隐藏文件和文件夹</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">skip_dotfiles</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;true&quot;</span></span></code></pre></div><p>关于配置文件的详细说明可以参考官方文档</p><p><a href="https://github.com/abraunegg/onedrive/blob/master/docs/usage.md" target="_blank" rel="noreferrer">https://github.com/abraunegg/onedrive/blob/master/docs/usage.md</a></p><h2 id="docker-命令简单介绍" tabindex="-1">docker 命令简单介绍 <a class="header-anchor" href="#docker-命令简单介绍" aria-label="Permalink to &quot;docker 命令简单介绍&quot;">​</a></h2><p><code>-it</code>：表示交互式操作，其中<code>i</code>是交互式操作，<code>t</code>是创建一个终端。</p><p><code>-d</code>：表示后台运行。</p><p><code>--name</code>：容器的名字，可以自定义。</p><p><code>-v</code>：挂载目录，左边是宿主机目录，右边是容器目录。</p><p><code>-e</code>：环境变量，用于传递参数。</p><p><code>--restart always</code>：表示容器退出后自动重启。</p>`,73)])])}const g=a(n,[["render",p]]);export{c as __pageData,g as default};
